#!/usr/bin/env python3
"""
Dependency Management Script for Python Projects
===============================================

This script provides utilities for managing Python dependency lock files
to ensure consistent versions across development and production environments.

Usage:
    python dependency_manager.py generate
    python dependency_manager.py update
    python dependency_manager.py verify
"""

import os
import sys
import subprocess
import hashlib
import json
from pathlib import Path
from typing import List, Dict, Optional

class DependencyManager:
    def __init__(self, project_root: str = "."):
        self.project_root = Path(project_root)
        self.requirements_file = self.project_root / "requirements.txt"
        self.poetry_lock_file = self.project_root / "poetry.lock"
        self.requirements_in_file = self.project_root / "requirements.in"
        self.pipfile = self.project_root / "Pipfile"
        self.pipfile_lock = self.project_root / "Pipfile.lock"
        
    def generate_requirements_txt(self) -> bool:
        """Generate requirements.txt with hashes from requirements.in"""
        if not self.requirements_in_file.exists():
            print("Error: requirements.in file not found")
            return False
            
        try:
            # Generate requirements.txt with hashes
            cmd = [
                "pip-compile", 
                "--generate-hashes",
                str(self.requirements_in_file),
                "-o", str(self.requirements_file)
            ]
            result = subprocess.run(cmd, capture_output=True, text=True, check=True)
            print("Generated requirements.txt with hashes")
            return True
        except subprocess.CalledProcessError as e:
            print(f"Error generating requirements.txt: {e.stderr}")
            return False
            
    def update_dependencies(self) -> bool:
        """Update dependencies in requirements.txt"""
        if not self.requirements_in_file.exists():
            print("Error: requirements.in file not found")
            return False
            
        try:
            # Update dependencies
            cmd = [
                "pip-compile",
                "--upgrade",
                "--generate-hashes",
                str(self.requirements_in_file),
                "-o", str(self.requirements_file)
            ]
            result = subprocess.run(cmd, capture_output=True, text=True, check=True)
            print("Updated dependencies in requirements.txt")
            return True
        except subprocess.CalledProcessError as e:
            print(f"Error updating dependencies: {e.stderr}")
            return False
            
    def generate_poetry_lock(self) -> bool:
        """Generate poetry.lock file"""
        try:
            cmd = ["poetry", "lock", "--no-update"]
            result = subprocess.run(cmd, capture_output=True, text=True, check=True)
            print("Generated poetry.lock file")
            return True
        except subprocess.CalledProcessError as e:
            print(f"Error generating poetry.lock: {e.stderr}")
            return False
            
    def update_poetry_lock(self) -> bool:
        """Update poetry.lock file with latest versions"""
        try:
            cmd = ["poetry", "lock"]
            result = subprocess.run(cmd, capture_output=True, text=True, check=True)
            print("Updated poetry.lock file")
            return True
        except subprocess.CalledProcessError as e:
            print(f"Error updating poetry.lock: {e.stderr}")
            return False
            
    def verify_dependencies(self) -> bool:
        """Verify that dependencies match lock files"""
        if self.requirements_file.exists():
            print("Verifying requirements.txt...")
            try:
                cmd = ["pip-check-reqs", str(self.requirements_file)]
                result = subprocess.run(cmd, capture_output=True, text=True, check=True)
                print("requirements.txt verification passed")
                return True
            except subprocess.CalledProcessError:
                print("requirements.txt verification failed")
                return False
                
        elif self.poetry_lock_file.exists():
            print("Verifying poetry.lock...")
            try:
                cmd = ["poetry", "check"]
                result = subprocess.run(cmd, capture_output=True, text=True, check=True)
                print("poetry.lock verification passed")
                return True
            except subprocess.CalledProcessError:
                print("poetry.lock verification failed")
                return False
                
        else:
            print("No lock file found")
            return False
            
    def get_dependency_info(self) -> Dict:
        """Get dependency information from lock files"""
        info = {
            "requirements_txt": self.requirements_file.exists(),
            "poetry_lock": self.poetry_lock_file.exists(),
            "requirements_in": self.requirements_in_file.exists()
        }
        
        if self.requirements_file.exists():
            with open(self.requirements_file, 'r') as f:
                lines = f.readlines()
                info["requirements_count"] = len([l for l in lines if l.strip() and not l.startswith('#')])
                
        if self.poetry_lock_file.exists():
            try:
                with open(self.poetry_lock_file, 'r') as f:
                    content = f.read()
                    info["poetry_version"] = "Poetry lock file"
            except Exception:
                info["poetry_version"] = "Error reading lock file"
                
        return info
        
    def create_sample_files(self):
        """Create sample dependency files"""
        # Create requirements.in
        if not self.requirements_in_file.exists():
            with open(self.requirements_in_file, 'w') as f:
                f.write("# Sample requirements.in\n")
                f.write("django>=4.0,<5.0\n")
                f.write("requests>=2.25.0\n")
                f.write("psycopg2-binary>=2.9.0\n")
                
        # Create requirements.txt if it doesn't exist
        if not self.requirements_file.exists():
            self.generate_requirements_txt()
            
        print("Created sample dependency files")

def main():
    manager = DependencyManager()
    
    if len(sys.argv) < 2:
        print("Usage: python dependency_manager.py [generate|update|verify|create]")
        sys.exit(1)
        
    command = sys.argv[1]
    
    if command == "generate":
        manager.generate_requirements_txt()
        manager.generate_poetry_lock()
    elif command == "update":
        manager.update_dependencies()
        manager.update_poetry_lock()
    elif command == "verify":
        manager.verify_dependencies()
    elif command == "create":
        manager.create_sample_files()
    else:
        print("Unknown command. Use: generate, update, verify, or create")
        sys.exit(1)

if __name__ == "__main__":
    main()